            if (window.AppModules && window.AppModules.View) {
                window.AppModules.View.unregisterLayer('detailPage');
                if (!window._isPopStateClosing) {
                    window._isProgrammaticBack = true;
                    history.back();
                }
            }

            setTimeout(() => page.classList.add('hidden'), 380);
